  ('social-worker-moex-03560', 'social-worker', 'social-worker-moex-113-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '甲教養院院長以提供服務對象最適切環境為由，將某次設施設備採購招標底標資料透露給特定廠 商。其行為屬於下列何種過失？', '["濫權", "瀆職", "怠職", "侵占"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:19+00:00", "source_pdf_sha1": "6a7820618b38", "answer_pdf_sha1": "b107fe954a39", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03561', 'social-worker', 'social-worker-moex-113-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '關於社會工作的假設前提，下列何者錯誤？', '["社會工作的介入可減緩問題的嚴重性", "肯定每個人存在的重要性", "接受人的互動過程中可能產生各種需求", "強調個體在與環境互動中，都應該先改變環境"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:19+00:00", "source_pdf_sha1": "6a7820618b38", "answer_pdf_sha1": "b107fe954a39", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03562', 'social-worker', 'social-worker-moex-113-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '癌症末期的服務對象要求社會工作者不要告知其家人真實病情，並決定放棄治療。上述情形係屬 何種社會工作倫理與價值議題？', '["關係界線", "價值涉入", "自我決定", "業務過失"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:19+00:00", "source_pdf_sha1": "6a7820618b38", "answer_pdf_sha1": "b107fe954a39", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03563', 'social-worker', 'social-worker-moex-113-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關道德相對論之主要觀點，下列何者錯誤？', '["因倫理之標準不一，故而需要有權力者訂定之", "因社會文化差異性，故而沒有普遍性倫理標準", "因個體生命經驗不同，故而有不同的價值", "因社會時代變遷，故而無法有絕對客觀的倫理標準"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:19+00:00", "source_pdf_sha1": "6a7820618b38", "answer_pdf_sha1": "b107fe954a39", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03564', 'social-worker', 'social-worker-moex-113-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '某社會工作者對經濟弱勢之受助家庭態度消極和不尊重，辯稱：「這些人都是福利依賴者，就算自 己積極幫助也沒有用，反正他們也不會想改變什麼。」依據Bandura（1986）的道德解離（moral disengagement）理論，上述情形屬於下列何種行為反應？', '["責任存有", "以權謀私", "責任分散", "非人性化"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:19+00:00", "source_pdf_sha1": "6a7820618b38", "answer_pdf_sha1": "b107fe954a39", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03565', 'social-worker', 'social-worker-moex-113-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '系統理論中強調對於服務對象面臨的問題須以「人在情境」的觀點剖析，下列敘述何者錯誤？', '["個人與社會系統間有交互關係", "各系統間存在著界線，各系統無法流動運行", "社會工作者與服務對象間的關係是具有協商性的夥伴關係", "個人會積極參與改變環境，環境也會形塑個人發展"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:19+00:00", "source_pdf_sha1": "6a7820618b38", "answer_pdf_sha1": "b107fe954a39", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03566', 'social-worker', 'social-worker-moex-113-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '關於社會工作者面對倫理衝突時，所依據之社會工作師倫理守則，下列敘述何者錯誤？', '["社會工作者完全依循服務對象的自我決定權", "社會工作者選擇保護服務對象的方法，不得與欲達成的目的有不相符合之損害", "社會工作者有多種達成目標的方法時，應選擇服務對象的最佳權益、最少損害為原則", "社會工作者採取之方法有助於爭取服務對象之利益"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:19+00:00", "source_pdf_sha1": "6a7820618b38", "answer_pdf_sha1": "b107fe954a39", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03567', 'social-worker', 'social-worker-moex-113-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '某癌末病人婉拒醫師採取安寧療護的建議，堅持要出院返家，不願再接受任何治療，經過社會工 作者會談後，尊重其意願，這是符合社會工作倫理的那項原則？', '["真誠原則", "最小傷害原則", "保護生命原則", "自由自主原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:19+00:00", "source_pdf_sha1": "6a7820618b38", "answer_pdf_sha1": "b107fe954a39", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03568', 'social-worker', 'social-worker-moex-113-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '當服務對象已死亡，社會工作者對於服務過程中的紀錄和報告應妥善保管，避免不當使用或外洩， 這是社會工作倫理所強調的何種原則？', '["維護隱私原則", "真誠原則", "平等原則", "個別化原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:19+00:00", "source_pdf_sha1": "6a7820618b38", "answer_pdf_sha1": "b107fe954a39", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03569', 'social-worker', 'social-worker-moex-113-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '服務對象是未成年之高二生，從小與爺爺相依為命。爺爺罹患重度失智症後，他為照顧爺爺經常 不穩定就學，最後成為中途離校生。學校社會工作者家訪後發現，服務對象將爺爺照顧得很好， 兩人目前是靠爺爺退休金和存款能維持生計。社工與服務對象會談後，其仍決定先照顧爺爺。社 工應以何種準則作為倫理抉擇？', '["不應尊重服務對象的決定，因為個人幸福權優先於他人的自由權", "應該尊重服務對象的決定，因為保護生命原則優先於自主自由原則", "不應尊重服務對象的決定，因為生活品質優先於自主自由原則", "應該尊重服務對象的決定，因為個人自由權優先於個人的基本幸福權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:19+00:00", "source_pdf_sha1": "6a7820618b38", "answer_pdf_sha1": "b107fe954a39", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
